   543→func sendFragments(
   544→	wr *pb.WatchResponse,
   545→	maxRequestBytes int,
   546→	sendFunc func(*pb.WatchResponse) error) error {
   547→	// no need to fragment if total request size is smaller
   548→	// than max request limit or response contains only one event
   549→	if wr.Size() < maxRequestBytes || len(wr.Events) < 2 {
   550→		return sendFunc(wr)
   551→	}
   552→
   553→	ow := *wr
   554→	ow.Events = make([]*mvccpb.Event, 0)
   555→	ow.Fragment = true
   556→
   557→	var idx int
   558→	for {
   559→		cur := ow
   560→		for _, ev := range wr.Events[idx:] {
   561→			cur.Events = append(cur.Events, ev)
   562→			if len(cur.Events) > 1 && cur.Size() >= maxRequestBytes {
   563→				cur.Events = cur.Events[:len(cur.Events)-1]
   564→				break
   565→			}
   566→			idx++
   567→		}
   568→		if idx == len(wr.Events) {
   569→			// last response has no more fragment
   570→			cur.Fragment = false
   571→		}
   572→		if err := sendFunc(&cur); err != nil {
   573→			return err
   574→		}
   575→		if !cur.Fragment {
   576→			break
   577→		}
   578→	}
   579→	return nil
   580→}
