   605→// FiltersFromRequest returns "mvcc.FilterFunc" from a given watch create request.
   606→func FiltersFromRequest(creq *pb.WatchCreateRequest) []mvcc.FilterFunc {
   607→	filters := make([]mvcc.FilterFunc, 0, len(creq.Filters))
   608→	for _, ft := range creq.Filters {
   609→		switch ft {
   610→		case pb.WatchCreateRequest_NOPUT:
   611→			filters = append(filters, filterNoPut)
   612→		case pb.WatchCreateRequest_NODELETE:
   613→			filters = append(filters, filterNoDelete)
